    }

    /**
     * Simple table with header
     */
    public function testSimpleTable(): void
    {
        $html = "<table><thead><tr><th>Name</th><th>Age</th></tr></thead><tbody><tr><td>Alice</td><td>30</td></tr></tbody></table>";
        $result = convert($html);
        $content = $result['content'] ?? '';

        $this->assertStringContainsString("Name", $content);
        $this->assertStringContainsString("Age", $content);
        $this->assertStringContainsString("Alice", $content);
        $this->assertStringContainsString("30", $content);
        $this->assertStringContainsString("|", $content);
        $this->assertStringContainsString("---", $content);
    }

    /**
